function TextFileList(props: {
  files: UploadFile[];
  onRemove: (uid: string) => void;
  onClearAll: () => void;
  showClearAll: boolean;
  classConfig?: string | UploadClassConfig;
  showTooltip?: boolean;
}) {
  const listId = createUniqueId();
  return (
    <div id={listId} class={cn('up06', cls(props.classConfig, 'textList'))}>
      <Show when={props.showClearAll && props.files.length > 1}>
        <div class={cn('up44', cls(props.classConfig, 'listHeader'))}>
          <span class={cn('up45', cls(props.classConfig, 'listCount'))}>
            {props.files.length} files
          </span>
          <button
            class={cn('up46', cls(props.classConfig, 'clearBtn'))}
            onClick={props.onClearAll}
            title="Remove all"
          >
            <Trash2 size={12} />
            Clear all
          </button>
        </div>
      </Show>
      <ul class="flex flex-col gap-2">
        <For each={props.files}>
          {file => {
            const badge = getFileBadge(file.type, file.name);
            return (
              <li>
                <FileUploadItem
                  file={file}
                  badge={badge}
                  onRemove={props.onRemove}
                  classConfig={props.classConfig}
                  showTooltip={props.showTooltip}
                />
              </li>
            );
          }}
        </For>
      </ul>
    </div>
  );
}

function FileUploadItem(props: {
  file: UploadFile;
  badge: { label: string; colorClass: string };
  onRemove: (uid: string) => void;
  classConfig?: string | UploadClassConfig;
  showTooltip?: boolean;
}) {
  const isUploading = () => props.file.status === 'uploading';

  return (
    <div class={cn('up07', cls(props.classConfig, 'textItem'))}>
      <div class="flex min-w-0 flex-1 items-center gap-2">
        <div class={cn('up08', props.badge.colorClass, cls(props.classConfig, 'textBadge'))}>
          {props.badge.label}
        </div>
        <Tooltip
          content={props.file.name}
          hidden={!props.showTooltip}
          class={{ root: 'up09' }}
          type="default"
        >
          <span class={cn('up09', cls(props.classConfig, 'textName'))}>{props.file.name}</span>
        </Tooltip>
        <div class={cn('up10', cls(props.classConfig, 'textSize'))}>
          {formatFileSize(props.file.size)}
        </div>

        <Switch>
          <Match when={isUploading()}>
            <Spinner class="size-5" />
          </Match>
          <Match when={props.file.status === 'done'}>
            <CircleCheck size={16} class="text-success" />
          </Match>
          <Match when={props.file.status === 'error'}>
            <CircleX size={16} class="text-error" />
          </Match>
        </Switch>

        <button
          class={cn('up57', cls(props.classConfig, 'removeBtn'))}
          onClick={() => props.onRemove(props.file.uid)}
          title="Remove"
        >
          <X size={16} />
        </button>
      </div>
    </div>
  );
}

function PictureFileList(props: {
  files: UploadFile[];
  onRemove: (uid: string) => void;
  onClearAll: () => void;
  showClearAll: boolean;
  getProgress: (uid: string) => Accessor<number>;
  classConfig?: string | UploadClassConfig;
}) {
  const [preview, setPreview] = createSignal<UploadFile | null>(null);

  return (
    <>
      <div class={cn('up47', cls(props.classConfig, 'pictureList'))}>
        <Show when={props.showClearAll && props.files.length > 1}>
          <div class={cn('up44', cls(props.classConfig, 'listHeader'))}>
            <span class={cn('up45', cls(props.classConfig, 'listCount'))}>
              {props.files.length} files
            </span>
            <button
              class={cn('up46', cls(props.classConfig, 'clearBtn'))}
              onClick={props.onClearAll}
              title="Remove all"
            >
              <Trash2 size={12} />
              Clear all
            </button>
          </div>
        </Show>
        <ul class="up48">
          <For each={props.files}>
            {file => (
              <li
                class={cn(
                  'up49',
                  file.status === 'uploading' && 'up49a',
                  file.status === 'error' && 'up49b',
                  cls(props.classConfig, 'pictureItem'),
                )}
              >
                <div class={cn('up50', cls(props.classConfig, 'pictureThumb'))}>
                  <Show
                    when={file.thumbUrl}
                    fallback={
                      <div
                        class={cn(
                          'up53',
                          getFileIconBg(file.type),
                          cls(props.classConfig, 'pictureIcon'),
                        )}
                      >
                        <span class={getFileIconColor(file.type)}>
                          {getFileIconNode(file.type, 20)}
                        </span>
                      </div>
                    }
                  >
                    <img src={file.thumbUrl} alt={file.name} />

                    <Show when={file.status === 'uploading'}>
                      <PictureThumbLoading />
                    </Show>

                    <Show when={file.status === 'done'}>
                      <button class="up52" onClick={() => setPreview(file)} title="Preview">
                        <ZoomIn size={14} />
                      </button>
                    </Show>
                  </Show>
                </div>

                <div class={cn('up54', cls(props.classConfig, 'pictureInfo'))}>
                  <div class="up36">
                    <span class="up21" title={file.name}>
                      {file.name}
                    </span>
                    <Show when={file.dimensions}>
                      <span class="up37">
                        {file.dimensions!.width} × {file.dimensions!.height} px
                      </span>
                    </Show>
                    <span class="up39">{formatFileSize(file.size)}</span>
                  </div>

                  <Show when={file.status === 'uploading'}>
                    <ProgressBar
                      percent={props.getProgress(file.uid)}
                      trackClass={cls(props.classConfig, 'progressTrack')}
                      fillClass={cls(props.classConfig, 'progressFill')}
                    />
                  </Show>

                  <Show when={file.status === 'done'}>
                    <span class="up24">
                      <CircleCheck size={11} />
                      Uploaded
                    </span>
                  </Show>

                  <Show when={file.status === 'error'}>
                    <span class="up23">Upload failed</span>
                  </Show>
                </div>

                <div class={cn('up55', cls(props.classConfig, 'pictureActions'))}>
                  <Show when={file.status === 'done' && file.thumbUrl}>
                    <button
                      class={cn('up56', cls(props.classConfig, 'actionBtn'))}
                      onClick={() => setPreview(file)}
                      title="Preview"
                    >
                      <Eye size={14} />
                    </button>
                  </Show>
                  <button
                    class={cn('up57', cls(props.classConfig, 'removeBtn'))}
                    onClick={() => props.onRemove(file.uid)}
                    title="Remove"
                  >
                    <X size={14} class="shrink-0" />
                  </button>
                </div>
              </li>
            )}
          </For>
        </ul>
      </div>

      <Show when={preview()}>
        <ImagePreview
          src={preview()!.thumbUrl!}
          imageName={preview()!.name}
          size={formatFileSize(preview()!.size)}
          onClose={() => setPreview(null)}
        />
      </Show>
    </>
  );
}

