function UploadBase(p: UploadProps) {
  p = mergeProps(
    {
      multiple: true,
      listType: 'text' as const,
      showUploadList: true,
      showTooltip: false,
    },
    p,
  );

  let inputRef!: HTMLInputElement;
  const { fileList, processFiles, removeFile, clearAll, getProgress } = useUpload(p);

  const triggerInput = () => inputRef.click();

  const handleInputChange = (e: Event) => {
    const input = e.currentTarget as HTMLInputElement;
    if (input.files?.length) processFiles(input.files);
    input.value = '';
  };

  const showAddButton = () => {
    if (!p.multiple && fileList().length >= 1) return false;
    if (p.maxCount && fileList().length >= p.maxCount) return false;
    return true;
  };

  const effectiveShowClearAll = () => p.showClearAll ?? p.multiple !== false;

  return (
    <div class={wrapperCls(p.class, 'up01')}>
      <input
        ref={inputRef}
        type="file"
        class="hidden"
        multiple={p.multiple}
        accept={p.accept}
        {...(p.directory ? { webkitdirectory: '' } : {})}
        onChange={handleInputChange}
      />

      <Switch>
        <Match when={p.listType === 'picture-card'}>
          <Show when={p.showUploadList}>
            <PictureCardFileList
              files={fileList()}
              onRemove={removeFile}
              onAdd={triggerInput}
              onClearAll={clearAll}
              showAddButton={showAddButton()}
              showClearAll={effectiveShowClearAll()}
              getProgress={getProgress}
              classConfig={p.class}
            />
          </Show>
          <Show when={!p.showUploadList}>
            <div onClick={triggerInput} class="w-fit cursor-pointer">
              {p.children}
            </div>
          </Show>
        </Match>
        <Match when={p.listType !== 'picture-card'}>
          <div
            onClick={showAddButton() ? triggerInput : undefined}
            class={showAddButton() ? 'w-fit cursor-pointer' : ''}
          >
            {p.children}
          </div>
          <Show when={p.showUploadList && fileList().length > 0}>
            <Switch>
              <Match when={p.listType === 'picture'}>
                <PictureFileList
                  files={fileList()}
                  onRemove={removeFile}
                  onClearAll={clearAll}
                  showClearAll={effectiveShowClearAll()}
                  getProgress={getProgress}
                  classConfig={p.class}
                />
              </Match>
              <Match when={p.listType === 'text'}>
                <TextFileList
                  files={fileList()}
                  onRemove={removeFile}
                  onClearAll={clearAll}
                  showClearAll={effectiveShowClearAll()}
                  classConfig={p.class}
                  showTooltip={p.showTooltip}
                />
              </Match>
            </Switch>
          </Show>
        </Match>
      </Switch>

      <Show when={p.errorMessage}>
        <div class={cn('up76', cls(p.class, 'errorMessage'))}>{p.errorMessage}</div>
      </Show>
    </div>
  );
}

function UploadDragger(p: UploadDraggerProps) {
  p = mergeProps(
    {
      multiple: true,
      listType: 'text' as const,
      showUploadList: true,
      hint: 'Support for a single or bulk upload',
      showTooltip: false,
    },
    p,
  );

  let inputRef!: HTMLInputElement;
  const [isDragging, setIsDragging] = createSignal(false);
  const { fileList, processFiles, removeFile, clearAll, getProgress } = useUpload(p);
  const effectiveShowClearAll = () => p.showClearAll ?? p.multiple !== false;

  const triggerInput = () => inputRef.click();

  const handleInputChange = (e: Event) => {
    const input = e.currentTarget as HTMLInputElement;
    if (input.files?.length) processFiles(input.files);
    input.value = '';
  };

  const handleDragOver = (e: DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const files = e.dataTransfer?.files;
    if (files?.length) processFiles(files);
  };

  const showAddButton = () => {
    if (!p.multiple && fileList().length >= 1) return false;
    if (p.maxCount && fileList().length >= p.maxCount) return false;
    return true;
  };

  return (
    <div class={wrapperCls(p.class, 'up01')}>
      <input
        ref={inputRef}
        type="file"
        class="hidden"
        multiple={p.multiple}
        accept={p.accept}
        {...(p.directory ? { webkitdirectory: '' } : {})}
        onChange={handleInputChange}
      />

      <Show when={p.listType === 'picture-card'}>
        <Show when={p.showUploadList}>
          <PictureCardFileList
            files={fileList()}
            onRemove={removeFile}
            onAdd={triggerInput}
            onClearAll={clearAll}
            showAddButton={showAddButton()}
            showClearAll={effectiveShowClearAll()}
            getProgress={getProgress}
            classConfig={p.class}
          />
        </Show>
      </Show>

      <Show when={p.listType !== 'picture-card'}>
        <Show when={showAddButton()}>
          <div
            class={cn('up02', isDragging() && 'up02a', cls(p.class, 'dragger'))}
            onClick={triggerInput}
            onDragOver={handleDragOver}
            onDragLeave={handleDragLeave}
            onDrop={handleDrop}
          >
            <div class={cn('up03', cls(p.class, 'draggerIcon'))}>
              <Show when={p.icon} fallback={<CloudUpload size={48} strokeWidth={1.5} />}>
                {p.icon}
              </Show>
            </div>
            <Show
              when={p.children}
              fallback={
                <>
                  <p class={cn('up04', cls(p.class, 'draggerTitle'))}>
                    Click or drag file to this area to upload
                  </p>
                  <p class={cn('up05', cls(p.class, 'draggerHint'))}>{p.hint}</p>
                </>
              }
            >
              {p.children}
            </Show>
          </div>
        </Show>

        <Show when={p.showUploadList && fileList().length > 0}>
          <Switch>
            <Match when={p.listType === 'picture'}>
              <PictureFileList
                files={fileList()}
                onRemove={removeFile}
                onClearAll={clearAll}
                showClearAll={effectiveShowClearAll()}
                getProgress={getProgress}
                classConfig={p.class}
              />
            </Match>
            <Match when={p.listType === 'text'}>
              <TextFileList
                files={fileList()}
                onRemove={removeFile}
                onClearAll={clearAll}
                showClearAll={effectiveShowClearAll()}
                classConfig={p.class}
                showTooltip={p.showTooltip}
              />
            </Match>
          </Switch>
        </Show>
      </Show>

      <Show when={p.errorMessage}>
        <div class={cn('up76', cls(p.class, 'errorMessage'))}>{p.errorMessage}</div>
      </Show>
    </div>
  );
}

export const Upload = UploadBase as UploadComponent;
Upload.Dragger = UploadDragger;
